# A beginner might write a function like this and think it's 'expert-level' Python:
def calculate_average(numbers):
    total = 0
    for num in numbers:
        total += num
    return total / len(numbers)

# While this works for simple cases, it lacks error handling, type hints, and efficiency checks.
